import React, { useMemo, useState } from 'react';
import { X, TrendingUp, TrendingDown, DollarSign, Calendar, BarChart3, ArrowUpRight, ArrowDownRight, Info } from 'lucide-react';
import { ArchivedDay, SaleItem, PurchaseInvoice } from '../types';

interface AnalyticsModalProps {
  history: ArchivedDay[];
  currentSales: SaleItem[];
  currentPurchases: PurchaseInvoice[];
  onClose: () => void;
}

export const AnalyticsModal: React.FC<AnalyticsModalProps> = ({ history, currentSales, currentPurchases, onClose }) => {
  const [daysCount, setDaysCount] = useState<7 | 15 | 30>(7);

  const data = useMemo(() => {
    // 1. Combine current day and history
    const todayDate = new Date().toLocaleDateString('ar-SY');

    // Calculate current day metrics
    const todayRevenue = currentSales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const todayPurchases = currentPurchases.reduce((sum, inv) => sum + inv.totalAmount, 0);
    const todayCOGS = currentSales.reduce((sum, item) => sum + ((item.costPrice || 0) * item.quantity), 0);
    const todayProfit = todayRevenue - todayCOGS - todayPurchases;

    const allData = [
      ...history.map(day => ({
        date: day.date,
        revenue: day.totalRevenue,
        purchases: (day.purchaseInvoices || []).reduce((sum, inv) => sum + inv.totalAmount, 0),
        profit: day.totalRevenue - (day.items || []).reduce((sum, item) => sum + ((item.costPrice || 0) * item.quantity), 0) - (day.purchaseInvoices || []).reduce((sum, inv) => sum + inv.totalAmount, 0),
        timestamp: day.timestamp
      })),
      {
        date: todayDate,
        revenue: todayRevenue,
        purchases: todayPurchases,
        profit: todayProfit,
        timestamp: Date.now()
      }
    ].sort((a, b) => a.timestamp - b.timestamp);

    // Filter by selected range
    return allData.slice(-daysCount);
  }, [history, currentSales, currentPurchases, daysCount]);

  const stats = useMemo(() => {
    const totalRevenue = data.reduce((s, d) => s + d.revenue, 0);
    const totalPurchases = data.reduce((s, d) => s + d.purchases, 0);
    const totalProfit = data.reduce((s, d) => s + d.profit, 0);
    return { totalRevenue, totalPurchases, totalProfit };
  }, [data]);

  // Chart configuration
  const chartHeight = 240;
  const chartWidth = 800;
  const padding = 40;

  const maxVal = Math.max(...data.flatMap(d => [d.revenue, d.purchases, d.profit, 1000]));

  const getX = (index: number) => padding + (index * (chartWidth - 2 * padding) / (data.length - 1 || 1));
  const getY = (value: number) => chartHeight - padding - ((value / (maxVal || 1)) * (chartHeight - 2 * padding));

  const points = {
    revenue: data.map((d, i) => `${getX(i)},${getY(d.revenue)}`).join(' '),
    purchases: data.map((d, i) => `${getX(i)},${getY(d.purchases)}`).join(' '),
    profit: data.map((d, i) => `${getX(i)},${getY(d.profit)}`).join(' ')
  };

  return (
    <div className="fixed inset-0 bg-black/90 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 animate-fade-up overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
          <div className="flex items-center gap-3">
             <div className="bg-[#FA8072]/20 p-2 rounded-xl">
                <BarChart3 className="text-[#FA8072]" size={24} />
             </div>
             <div>
                <h3 className="font-bold text-xl text-white">مركز التحليلات البيانية</h3>
                <p className="text-gray-500 text-xs">مراقبة الأداء المالي والأرباح الصافية</p>
             </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={24} className="text-gray-400" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 space-y-6">

          {/* Controls & Summary */}
          <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
             <div className="flex bg-gray-900 p-1 rounded-xl border border-gray-700 shrink-0">
                {[7, 15, 30].map(n => (
                   <button 
                    key={n} 
                    onClick={() => setDaysCount(n as any)} 
                    className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${daysCount === n ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
                   >
                     آخر {n} أيام
                   </button>
                ))}
             </div>

             <div className="grid grid-cols-3 gap-3 w-full lg:w-auto">
                <div className="bg-blue-600/10 border border-blue-500/20 px-4 py-2 rounded-xl">
                   <span className="text-[10px] text-blue-400 font-bold block">المبيعات</span>
                   <span className="text-sm font-black text-white">{stats.totalRevenue.toLocaleString()}</span>
                </div>
                <div className="bg-red-600/10 border border-red-500/20 px-4 py-2 rounded-xl">
                   <span className="text-[10px] text-red-400 font-bold block">المشتريات</span>
                   <span className="text-sm font-black text-white">{stats.totalPurchases.toLocaleString()}</span>
                </div>
                <div className="bg-green-600/10 border border-green-500/20 px-4 py-2 rounded-xl">
                   <span className="text-[10px] text-green-400 font-bold block">الأرباح</span>
                   <span className="text-sm font-black text-white">{stats.totalProfit.toLocaleString()}</span>
                </div>
             </div>
          </div>

          {/* SVG Chart Section */}
          <div className="bg-gray-900/50 rounded-2xl border border-gray-700 p-4 relative">
             <div className="flex items-center gap-6 mb-4 px-2">
                <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-blue-500"></div><span className="text-[10px] text-gray-400 font-bold">المبيعات</span></div>
                <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-red-500"></div><span className="text-[10px] text-gray-400 font-bold">المشتريات</span></div>
                <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-green-500"></div><span className="text-[10px] text-gray-400 font-bold">صافي الربح</span></div>
             </div>

             <div className="relative overflow-x-auto pb-4">
                <svg viewBox={`0 0 ${chartWidth} ${chartHeight}`} className="w-full h-auto min-w-[600px]">
                    {/* Grid Lines */}
                    {[0, 1, 2, 3, 4].map(i => {
                        const y = padding + (i * (chartHeight - 2 * padding) / 4);
                        return (
                            <line key={i} x1={padding} y1={y} x2={chartWidth - padding} y2={y} stroke="#374151" strokeWidth="1" strokeDasharray="4 4" />
                        );
                    })}

                    {/* Gradient Fills */}
                    <defs>
                        <linearGradient id="grad-revenue" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="0%" stopColor="#3B82F6" stopOpacity="0.2" />
                            <stop offset="100%" stopColor="#3B82F6" stopOpacity="0" />
                        </linearGradient>
                        <linearGradient id="grad-profit" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="0%" stopColor="#10B981" stopOpacity="0.2" />
                            <stop offset="100%" stopColor="#10B981" stopOpacity="0" />
                        </linearGradient>
                    </defs>

                    <polyline points={`${padding},${chartHeight-padding} ${points.revenue} ${chartWidth-padding},${chartHeight-padding}`} fill="url(#grad-revenue)" />
                    <polyline points={`${padding},${chartHeight-padding} ${points.profit} ${chartWidth-padding},${chartHeight-padding}`} fill="url(#grad-profit)" />

                    {/* Lines */}
                    <polyline points={points.revenue} fill="none" stroke="#3B82F6" strokeWidth="3" strokeLinejoin="round" />
                    <polyline points={points.purchases} fill="none" stroke="#EF4444" strokeWidth="3" strokeLinejoin="round" />
                    <polyline points={points.profit} fill="none" stroke="#10B981" strokeWidth="4" strokeLinejoin="round" />

                    {/* Nodes and Labels */}
                    {data.map((d, i) => (
                        <g key={i}>
                            <circle cx={getX(i)} cy={getY(d.revenue)} r="4" fill="#3B82F6" />
                            <circle cx={getX(i)} cy={getY(d.profit)} r="5" fill="#10B981" />
                            <text x={getX(i)} y={chartHeight - 10} textAnchor="middle" fill="#9CA3AF" fontSize="10" fontWeight="bold">
                                {d.date.split('/')[0]}/{d.date.split('/')[1]}
                            </text>
                        </g>
                    ))}
                </svg>
             </div>
          </div>

          {/* Cards Analysis */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div className="bg-gray-800/50 p-5 rounded-2xl border border-gray-700 flex items-center justify-between">
                <div>
                   <p className="text-gray-500 text-xs font-bold mb-1">متوسط الربح اليومي</p>
                   <h4 className="text-2xl font-black text-white">{(stats.totalProfit / data.length).toLocaleString(undefined, {maximumFractionDigits:0})} <span className="text-[10px] text-gray-500">ل.س</span></h4>
                </div>
                <div className="bg-green-500/10 p-3 rounded-full text-green-500">
                   <ArrowUpRight size={24} />
                </div>
             </div>

             <div className="bg-gray-800/50 p-5 rounded-2xl border border-gray-700 flex items-center justify-between">
                <div>
                   <p className="text-gray-500 text-xs font-bold mb-1">نسبة التكاليف للمبيعات</p>
                   <h4 className="text-2xl font-black text-white">{((stats.totalPurchases / (stats.totalRevenue || 1)) * 100).toFixed(1)}%</h4>
                </div>
                <div className="bg-orange-500/10 p-3 rounded-full text-orange-500">
                   <TrendingDown size={24} />
                </div>
             </div>
          </div>

          <div className="flex items-center gap-2 bg-blue-900/10 p-3 rounded-xl border border-blue-500/20 text-blue-400">
             <Info size={16} />
             <p className="text-[10px] font-bold">الربح الصافي = (المبيعات - تكلفة المواد) - المشتريات الخارجية. ملاحظة: الأرباح تظهر بناءً على القيم المدخلة في النظام.</p>
          </div>
        </div>

        <div className="p-4 bg-gray-900/80 border-t border-gray-700 text-center">
           <p className="text-gray-600 text-[10px] font-bold">نظام التحليل الذكي v1.0 &copy; {new Date().getFullYear()}</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
